DROP TABLE IF EXISTS quiz
DROP TABLE IF EXISTS stats
CREATE TABLE quiz ("Nome quiz" TEXT,"Nome corso" TEXT, "Apertura" TEXT, "Chiusura" TEXT, "Aperto per" TEXT, "Numero di primi tentativi completati e valutati" INTEGER, "Numero totale dei tentativi completi valutati" INTEGER, "Voto medio dei primi tentativi" TEXT, "Voto medio di tutti i tentativi" TEXT, "Media delle valutazioni degli ultimi tentativi" TEXT, "Media delle valutazioni dei tentativi migliori" TEXT, "Mediana dei voti (per tentativo migliore)" TEXT, "Deviazione standard (per tentativo migliore)" TEXT, "Mediana dei voti (per ultimi tentativi)" TEXT, "Deviazione standard (per ultimi tentativi)" TEXT, "Asimmetria della distribuzione dei voti (per ultimi tentativi)" TEXT, "Curtosi della distribuzione dei voti (per ultimi tentativi)" TEXT, "Coefficiente di consistenza interna (per ultimi tentativi)" TEXT, "Quoziente d'errore (per ultimi tentativi)" TEXT, "Errore standard (per ultimi tentativi)" TEXT)
CREATE TABLE stats ("Nome quiz" TEXT,"Nome corso" TEXT, "Apertura" TEXT, "Q" INTEGER, "Tipo di domanda" TEXT, "Nome della domanda" TEXT, "Tentativi" INTEGER, "Indice di abilita" TEXT, "Deviazione standard" TEXT, "Indice delle risposte date a caso" TEXT, "Peso previsto" TEXT, "Peso effettivo" TEXT, "Indice di discriminazione" TEXT, "Efficienza discriminante" TEXT)